//! Fixture replay for the beta workspace-trust projection.
//!
//! The fixtures live under `fixtures/security/m3/workspace_trust/` and are
//! generated by the `aureline_shell_workspace_trust_beta` headless inspector,
//! so checked-in JSON stays a literal projection of the seeded
//! `WorkspaceTrustBetaPage`.

use aureline_auth::{CapabilityAuthorityClass, LaunchWedgeCapabilityFamily};
use aureline_shell::workspace_trust_beta::{
    audit_workspace_trust_beta_rows, seeded_workspace_trust_beta_page,
    validate_workspace_trust_beta_page, WorkspaceTrustBetaDefectKind, WorkspaceTrustBetaPage,
    WorkspaceTrustBetaRenderSummary, WorkspaceTrustBetaSupportExport, WorkspaceTrustBetaSupportRow,
    WORKSPACE_TRUST_BETA_SCHEMA_VERSION, WORKSPACE_TRUST_BETA_SHARED_CONTRACT_REF,
    WORKSPACE_TRUST_BETA_SURFACE_FAMILIES,
};

const FIXTURE_DIR: &str = concat!(
    env!("CARGO_MANIFEST_DIR"),
    "/../../fixtures/security/m3/workspace_trust"
);

fn load<T: serde::de::DeserializeOwned>(filename: &str) -> T {
    let path = format!("{}/{}", FIXTURE_DIR, filename);
    let body =
        std::fs::read_to_string(&path).unwrap_or_else(|err| panic!("failed to read {path}: {err}"));
    serde_json::from_str(&body).unwrap_or_else(|err| panic!("failed to parse {path}: {err}"))
}

#[test]
fn page_fixture_matches_seeded_builder() {
    let from_file: WorkspaceTrustBetaPage = load("page.json");
    let from_code = seeded_workspace_trust_beta_page();
    assert_eq!(
        from_file, from_code,
        "fixture must be a literal projection of the seeded page; regenerate via the headless bin"
    );
}

#[test]
fn page_fixture_validates_with_zero_defects() {
    let page: WorkspaceTrustBetaPage = load("page.json");
    assert_eq!(
        page.shared_contract_ref,
        WORKSPACE_TRUST_BETA_SHARED_CONTRACT_REF
    );
    assert_eq!(page.schema_version, WORKSPACE_TRUST_BETA_SCHEMA_VERSION);
    assert!(page.defects.is_empty());
    validate_workspace_trust_beta_page(&page).expect("seeded page must validate");
    assert_eq!(page.rows.len(), WORKSPACE_TRUST_BETA_SURFACE_FAMILIES.len());
}

#[test]
fn rows_and_support_rows_round_trip() {
    let page: WorkspaceTrustBetaPage = load("page.json");
    let support_rows: Vec<WorkspaceTrustBetaSupportRow> = load("support_rows.json");
    assert_eq!(page.rows.len(), support_rows.len());
    assert_eq!(page.support_rows, support_rows);
    assert!(audit_workspace_trust_beta_rows(&page.rows, &support_rows).is_empty());

    let floor = page
        .rows
        .iter()
        .find(|row| row.surface_family == LaunchWedgeCapabilityFamily::EditorReadWrite)
        .expect("editor row");
    assert_eq!(
        floor.restricted_authority,
        CapabilityAuthorityClass::Allowed
    );

    let ai_apply = page
        .rows
        .iter()
        .find(|row| row.surface_family == LaunchWedgeCapabilityFamily::AiApplyMutation)
        .expect("ai apply row");
    assert_eq!(
        ai_apply.restricted_authority,
        CapabilityAuthorityClass::BlockedPendingTrust
    );
    assert!(ai_apply
        .escalation_cue_tokens
        .contains(&"request_trust_grant_session_only".to_owned()));
}

#[test]
fn support_export_round_trips_through_validator() {
    let export: WorkspaceTrustBetaSupportExport = load("support_export.json");
    assert!(export.raw_private_material_excluded);
    assert!(export.defect_kinds_present.is_empty());
    assert_eq!(
        export.shared_contract_ref,
        WORKSPACE_TRUST_BETA_SHARED_CONTRACT_REF
    );
}

#[test]
fn drill_trust_bypass_replays_typed_defect() {
    let page: WorkspaceTrustBetaPage = load("drill_trust_bypass.json");
    let recomputed = audit_workspace_trust_beta_rows(&page.rows, &page.support_rows);
    assert_eq!(recomputed, page.defects);
    assert!(recomputed.iter().any(|defect| defect.defect_kind
        == WorkspaceTrustBetaDefectKind::RunOrMutationAllowedBeforeTrust));
}

#[test]
fn drill_support_drift_replays_typed_defect() {
    let page: WorkspaceTrustBetaPage = load("drill_support_drift.json");
    let recomputed = audit_workspace_trust_beta_rows(&page.rows, &page.support_rows);
    assert_eq!(recomputed, page.defects);
    assert!(recomputed.iter().any(
        |defect| defect.defect_kind == WorkspaceTrustBetaDefectKind::SupportRowVocabularyDrift
    ));
}

#[test]
fn drill_public_fallback_replays_typed_defect() {
    let page: WorkspaceTrustBetaPage = load("drill_public_fallback.json");
    let recomputed = audit_workspace_trust_beta_rows(&page.rows, &page.support_rows);
    assert_eq!(recomputed, page.defects);
    assert!(recomputed
        .iter()
        .any(|defect| defect.defect_kind
            == WorkspaceTrustBetaDefectKind::HiddenPublicEndpointFallback));
}

#[test]
fn render_summary_matches_page_summary() {
    let from_file: WorkspaceTrustBetaRenderSummary = load("render_summary.json");
    let page: WorkspaceTrustBetaPage = load("page.json");
    let from_page = WorkspaceTrustBetaRenderSummary::from_page(&page);
    assert_eq!(from_file, from_page);
}
